import{_ as a,a as d,b as t,c as o,d as i,e as n,f as l,g as r}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as s,o as p,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Федеративный распределенный индекс","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Other/federated-distributed-index.md","filePath":"ru-RU/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),u={name:"ru-RU/Other/federated-distributed-index.md"};function b(f,e,m,x,g,q){return p(),c("div",null,[...e[0]||(e[0]=[h('<h1 id="федеративныи-распределенныи-индекс" tabindex="-1">Федеративный распределенный индекс <a class="header-anchor" href="#федеративныи-распределенныи-индекс" aria-label="Permalink to &quot;Федеративный распределенный индекс&quot;">​</a></h1><p>Федеративный распределенный индекс позволяет нескольким сайтам ImgBed обмениваться списками файлов.</p><p>Проще говоря:</p><ul><li>вы можете делиться выбранными папками своего сайта с другими;</li><li>можете присоединиться к другому узлу и синхронизировать его общий список файлов в свою админ-панель;</li><li>federated files в основном предназначены для просмотра, поиска и открытия ссылок. Они не перезагружаются в ваше собственное хранилище.</li></ul><h2 id="где-это-настраивается" tabindex="-1">Где это настраивается <a class="header-anchor" href="#где-это-настраивается" aria-label="Permalink to &quot;Где это настраивается&quot;">​</a></h2><p>Откройте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Локальный federation node" loading="lazy"></p><p>На странице есть три вкладки:</p><table tabindex="0"><thead><tr><th>Вкладка</th><th>Назначение</th></tr></thead><tbody><tr><td>Local Node</td><td>Включить свой node, подтвердить публичный домен, выбрать общие папки и обновить outbound index</td></tr><tr><td>Nodes I Joined</td><td>Управлять другими ImgBed nodes, к которым вы присоединились</td></tr><tr><td>Nodes Joining Me</td><td>Управлять запросами от других, кто хочет присоединиться к вашему node</td></tr></tbody></table><h2 id="первичная-настроика" tabindex="-1">Первичная настройка <a class="header-anchor" href="#первичная-настроика" aria-label="Permalink to &quot;Первичная настройка&quot;">​</a></h2><ol><li>Откройте <code>Local Node</code>.</li><li>Включите <code>Enable</code>.</li><li>В <code>Sync folders</code> выберите папки, которыми хотите поделиться.</li><li>Нажмите <code>Update Outbound Index</code>.</li><li>Если ImgBed обнаружит смену домена, подтвердите, что текущий домен правильный.</li></ol><p>Можно выбрать несколько sync folders.</p><p>Если список sync folder пуст, распространяются все папки.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain — это URL сайта, через который другие nodes обращаются к вашему node.</p><p>ImgBed определяет его автоматически. Вводить вручную не нужно. При первом обновлении индекса ImgBed попросит подтвердить, является ли текущий URL доступа production-доменом.</p><p>Если позже изменить домен, обновление индекса снова попросит подтверждение.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders определяют, какие файлы распространяются для federation nodes.</p><p>Например, если выбрать только:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>другие nodes увидят только файлы в этих двух директориях.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>Обновляет список файлов, который другие nodes могут синхронизировать с вашего сайта.</p><p>Используйте это, когда:</p><ul><li>вы впервые включаете federation;</li><li>загрузили файлы, которыми хотите поделиться;</li><li>изменили sync folders;</li><li>изменили public domain и нужно его подтвердить.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> — место, где вы подписываетесь на другие nodes.</p><p><img src="`+d+'" alt="Nodes I joined" loading="lazy"></p><h3 id="запрос-на-присоединение-к-другому-node" tabindex="-1">Запрос на присоединение к другому node <a class="header-anchor" href="#запрос-на-присоединение-к-другому-node" aria-label="Permalink to &quot;Запрос на присоединение к другому node&quot;">​</a></h3><ol><li>Попросите владельца другого сайта дать invitation link.</li><li>Вставьте его в поле ввода.</li><li>Нажмите <code>Request to Join</code>.</li><li>Дождитесь, пока другой владелец одобрит запрос в своей админ-панели.</li></ol><p>После одобрения статус node станет approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> синхронизирует списки файлов из nodes, к которым вы присоединились.</p><p>Используйте это, когда:</p><ul><li>другой владелец только что одобрил ваш запрос;</li><li>другой владелец сообщил, что общий контент обновлен;</li><li>вы хотите обновить все подключенные federation file lists.</li></ul><p>Чтобы обновить только один node, нажмите <code>Update Index</code> на его карточке.</p><p><img src="'+t+'" alt="Обновление индекса" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>Если больше не хотите синхронизировать node, нажмите <code>Unsubscribe</code>.</p><p>После отписки federated index этого node будет удален с вашего локального сайта.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> — место для обработки запросов от других.</p><p><img src="'+o+'" alt="Nodes joining me" loading="lazy"></p><h3 id="создание-invitation-link" tabindex="-1">Создание invitation link <a class="header-anchor" href="#создание-invitation-link" aria-label="Permalink to &quot;Создание invitation link&quot;">​</a></h3><ol><li>Убедитесь, что local node включен.</li><li>Нажмите <code>Update Outbound Index</code> хотя бы один раз, чтобы ImgBed подтвердил public domain.</li><li>Откройте <code>Nodes Joining Me</code>.</li><li>Нажмите <code>Reset Invitation Link</code>.</li><li>Скопируйте invitation link и отправьте его другому владельцу.</li></ol><p>Если invitation link пуст, public domain обычно еще не подтвержден. Вернитесь в <code>Local Node</code> и нажмите <code>Update Outbound Index</code>.</p><h3 id="обработка-запросов" tabindex="-1">Обработка запросов <a class="header-anchor" href="#обработка-запросов" aria-label="Permalink to &quot;Обработка запросов&quot;">​</a></h3><p>Когда кто-то отправляет запрос, он появляется в списке <code>Nodes Joining Me</code>.</p><table tabindex="0"><thead><tr><th>Действие</th><th>Значение</th></tr></thead><tbody><tr><td>Approve</td><td>Позволяет другому node синхронизировать ваш общий список файлов</td></tr><tr><td>Reject</td><td>Отклоняет запрос на присоединение</td></tr><tr><td>Delete</td><td>Удаляет завершенную запись</td></tr><tr><td>Check Status</td><td>Проверяет, поддерживает ли другая сторона эту связь</td></tr></tbody></table><p>После одобрения другая сторона все равно должна нажать <code>Update Inbound Index</code>, прежде чем ваши общие файлы появятся у нее.</p><p><img src="'+i+'" alt="Одобрение приглашенного node" loading="lazy"></p><h2 id="сообщения" tabindex="-1">Сообщения <a class="header-anchor" href="#сообщения" aria-label="Permalink to &quot;Сообщения&quot;">​</a></h2><p>После одобрения связи нажмите <code>Message</code> на карточке node.</p><p>Сообщения нужны только для общения по поводу federation relationship. Они не меняют файлы, теги, директории или permissions.</p><p><img src="'+n+'" alt="Сообщения" loading="lazy"></p><h2 id="просмотр-federated-files" tabindex="-1">Просмотр federated files <a class="header-anchor" href="#просмотр-federated-files" aria-label="Permalink to &quot;Просмотр federated files&quot;">​</a></h2><p>После завершения синхронизации вернитесь к списку файлов в админ-панели.</p><p>Вверху страницы можно переключаться между локальными файлами и federated files. В federated files можно просматривать синхронизированный контент.</p><p>Federated files предназначены в основном для просмотра, поиска, preview и копирования ссылок. Это не локальные файлы, поэтому их нельзя перемещать, удалять, пере тегировать или резервно копировать со своего сайта.</p><p><img src="'+l+'" alt="Federated files в админ-панели" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="почему-система-просит-подать-заявку-заново-потому-что-relationship-record-отсутствует" tabindex="-1">Почему система просит подать заявку заново, потому что relationship record отсутствует? <a class="header-anchor" href="#почему-система-просит-подать-заявку-заново-потому-что-relationship-record-отсутствует" aria-label="Permalink to &quot;Почему система просит подать заявку заново, потому что relationship record отсутствует?&quot;">​</a></h3><p>Обычно это значит, что другая сторона удалила вас и убрала запись, поэтому связь больше не находится. Отправьте новый join request.</p><p><img src="'+r+'" alt="Повторная заявка, когда relationship record отсутствует" loading="lazy"></p><h3 id="почему-после-присоединения-я-не-вижу-фаилы" tabindex="-1">Почему после присоединения я не вижу файлы? <a class="header-anchor" href="#почему-после-присоединения-я-не-вижу-фаилы" aria-label="Permalink to &quot;Почему после присоединения я не вижу файлы?&quot;">​</a></h3><p>Проверьте:</p><ol><li>Другой владелец одобрил ваш запрос.</li><li>Другой владелец нажал <code>Update Outbound Index</code>.</li><li>Вы нажали <code>Update Inbound Index</code>.</li><li>Sync folders другого владельца содержат директории, которыми он хочет поделиться.</li></ol><h3 id="что-делать-когда-обнаружена-смена-домена" tabindex="-1">Что делать, когда обнаружена смена домена? <a class="header-anchor" href="#что-делать-когда-обнаружена-смена-домена" aria-label="Permalink to &quot;Что делать, когда обнаружена смена домена?&quot;">​</a></h3><p>Если вы сейчас открыли админ-панель через production-домен, подтвердите и продолжайте.</p><p>Если используется временный адрес, отмените, откройте админ-панель через production-домен и попробуйте снова.</p><h3 id="что-означает-пустои-список-sync-folder" tabindex="-1">Что означает пустой список Sync Folder? <a class="header-anchor" href="#что-означает-пустои-список-sync-folder" aria-label="Permalink to &quot;Что означает пустой список Sync Folder?&quot;">​</a></h3><p>Пустой список sync folder означает, что распространяются все папки.</p><p>Чтобы распространять только отдельные директории, выберите их вручную.</p><h3 id="разница-между-outbound-и-inbound-index-updates" tabindex="-1">Разница между Outbound и Inbound Index Updates <a class="header-anchor" href="#разница-между-outbound-и-inbound-index-updates" aria-label="Permalink to &quot;Разница между Outbound и Inbound Index Updates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Кнопка</th><th>Простое значение</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Обновляет то, что другие могут синхронизировать от меня</td></tr><tr><td>Update Inbound Index</td><td>Обновляет то, что я синхронизировал от других</td></tr></tbody></table>',78)])])}const y=s(u,[["render",b]]);export{_ as __pageData,y as default};
